238	            InData(31 downto 0)     => AxiM_RdDat_Data,
239	            InData(32)              => Last,
240	            InVld                   => AxiM_RdDat_Vld,
241	            InRdy                   => Fifo_Rdy,
242	            OutData(31 downto 0)    => AxiS_Data,
243	            OutData(32)             => AxiS_Last,
244	            OutVld                  => AxiS_Vld,
245	            OutRdy                  => AxiS_Rdy,
246	            OutLevel                => AxiS_Level(log2ceil(MaxRegCount_g*MinBuffers_g) downto 0)
